import hashlib import json from fastapi import FastAPI, Response
app = FastAPI()
@app.get("/api/products/{product_id}") async def get_product(product_id: str, response: Response): product = await db.get_product(product_id) etag = hashlib.md5(json.dumps(product, sort_keys=True).encode()).hexdigest() response.headers["Cache-Control"] = "public, max-age=300, stale-while-revalidate=60" response.headers["ETag"] = f'"{etag}"' return product
@app.get("/api/user/profile") async def get_profile(response: Response): response.headers["Cache-Control"] = "private, max-age=0, must-revalidate" return await db.get_current_user()
